struct UnionFind {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        UnionFind {
            parent: (0..size).collect(),
            rank: vec![0; size],
        }
    }

    fn find(&mut self, u: usize) -> usize {
        if self.parent[u] != u {
            self.parent[u] = self.find(self.parent[u]);
        }
        self.parent[u]
    }

    fn union(&mut self, u: usize, v: usize) -> bool {
        let root_u = self.find(u);
        let root_v = self.find(v);
        if root_u == root_v {
            return false;
        }
        if self.rank[root_u] > self.rank[root_v] {
            self.parent[root_v] = root_u;
        } else if self.rank[root_u] < self.rank[root_v] {
            self.parent[root_u] = root_v;
        } else {
            self.parent[root_v] = root_u;
            self.rank[root_u] += 1;
        }
        true
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let must = edge[3];
        if must == 1 {
            must_edges.push((u, v, s));
        } else {
            optional_edges.push((u, v, s));
        }
    }

    let mut uf = UnionFind::new(n);
    let mut components = n;

    // Process must edges first
    for &(u, v, _) in &must_edges {
        if uf.union(u, v) {
            components -= 1;
        }
    }

    if components == 1 {
        let min_strength = must_edges.iter().map(|&(_, _, s)| s).min().unwrap();
        return min_strength;
    }

    // Sort optional edges in descending order of strength
    optional_edges.sort_by(|a, b| b.2.cmp(&a.2));

    let mut left = 1;
    let mut right = 1_000_000;
    let mut answer = -1;

    while left <= right {
        let mid = (left + right) / 2;
        let mut temp_uf = UnionFind::new(n);
        let mut temp_components = n;
        let mut used_k = 0;

        // Process must edges
        for &(u, v, s) in &must_edges {
            if s >= mid {
                if temp_uf.union(u, v) {
                    temp_components -= 1;
                }
            }
        }

        // Process optional edges
        for &(u, v, s) in &optional_edges {
            if s >= mid {
                if temp_uf.union(u, v) {
                    temp_components -= 1;
                }
            } else if s * 2 >= mid && used_k < k {
                if temp_uf.union(u, v) {
